let targetCar = {
  make: "Toyota",
  model: "Camry",
  year: 2024
};

console.log("We are looking for a " + targetCar.year + " " + targetCar.make);

// We can also use Dot Notation to overwrite values!
targetCar.year = 1999;
console.log("Wait, it is actually a " + targetCar.year);
